import { useEffect, useState } from "react";
import PageHeader from "../components/PageHeader";
import { getAdminLogs } from "../services/api";

export default function AdminLogsPage() {
  const [logs, setLogs] = useState([]);

  useEffect(() => {
    const load = async () => setLogs(await getAdminLogs());
    load();
  }, []);

  return (
    <>
      <PageHeader title="Chat Logs Monitoring" description="Review interactions and assistant output in an isolated log monitoring screen." />
      <div className="panel">
        <div className="table-wrap">
          <table>
            <thead>
              <tr><th>User</th><th>Message</th><th>Bot Response</th><th>Timestamp</th></tr>
            </thead>
            <tbody>
              {logs.map((log) => (
                <tr key={log.id}>
                  <td>{log.user.name}</td>
                  <td>{log.user_message}</td>
                  <td>{log.bot_response}</td>
                  <td>{new Date(log.created_at).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
}
